blend_hex <- function(hex, target, amount) {
  rgb1 <- grDevices::col2rgb(hex) / 255
  rgb2 <- grDevices::col2rgb(target) / 255
  rgb <- rgb1 * (1 - amount) + rgb2 * amount
  grDevices::rgb(rgb[1], rgb[2], rgb[3])
}
pool_prevalence_cols <- unlist(lapply(names(pool_cols), function(pool) {
  # Figure 3f uses hue for pool identity and shade for prevalence category:
  # dark = common, medium = shared, light = pool-unique.
  cols <- c(
    "Pool-unique" = blend_hex(pool_cols[[pool]], "white", 0.55),
    Shared = pool_cols[[pool]],
    Common = blend_hex(pool_cols[[pool]], "black", 0.28)
  )
  setNames(cols, paste(pool, names(cols), sep = "::"))
}))
pool_prevalence_levels <- as.vector(vapply(
