make_pca <- function(state_name, title) {
  d <- pca %>%
    filter(state == state_name) %>%
    mutate(ellipse_group = interaction(combined_pool_id, processing_level, drop = TRUE))
  ellipse_groups <- d %>% count(ellipse_group) %>% filter(n >= 4) %>% pull(ellipse_group)
  ellipse_data <- d %>% filter(ellipse_group %in% ellipse_groups)
  stat <- permanova %>% filter(state == state_name, term != "Residual", term != "Total") %>% slice_head(n = 1)
  p <- ggplot(d, aes(PC1, PC2, colour = combined_pool_id)) +
    geom_point(aes(shape = if (state_name == "Fractionated") processing_level else NULL), size = 1.7, alpha = 0.8)
  if (state_name == "Fractionated") {
    p <- p +
      stat_ellipse(
        data = ellipse_data,
        aes(group = ellipse_group),
        type = "norm", level = 0.8, linewidth = 0.5, show.legend = FALSE
      )
  }
  p +
    scale_colour_manual(values = pool_cols, name = "Pool") +
    labs(
      title = title,
      x = paste0("PC1 (", percent(d$pc1_variance[[1]], accuracy = 0.1), ")"),
      y = paste0("PC2 (", percent(d$pc2_variance[[1]], accuracy = 0.1), ")"),
      shape = "Fraction type"
    )
}
