volcano <- volcano %>%
  mutate(plot_p = -log10(pmax(fdr, 1e-300)), short_label = if_else(fdr < 0.01 & abs(effect) >= 1, coalesce(compound.name, annotation_id), NA_character_))
make_volcano <- function(state_name) {
  d <- volcano %>% filter(state == state_name)
  ggplot(d, aes(effect, plot_p, colour = direction)) +
    geom_point(size = 0.7, alpha = 0.55) +
    geom_vline(xintercept = c(-1, 1), linetype = 2, linewidth = 0.3) +
    geom_hline(yintercept = -log10(0.05), linetype = 2, linewidth = 0.3) +
    ggrepel::geom_text_repel(
      data = d %>% filter(!is.na(short_label)),
      aes(label = short_label), max.overlaps = 8, size = 3.75, box.padding = 0.3, show.legend = FALSE
    ) +
    scale_colour_manual(
      values = direction_cols,
      breaks = c("Higher in Pool_1", "Higher in Pool_4", "Not significant"),
      labels = c("Higher in Pool 1", "Higher in Pool 4", "Not significant")
    ) +
    labs(title = paste(state_name, "differential features"), x = "log2 fold change\n(Pool 4 / Pool 1)", y = "-log10(BH-adjusted FDR)", colour = "Direction") +
    theme(
      legend.position = "inside",
      legend.position.inside = c(0.56, 0.96),
      legend.direction = "horizontal",
      legend.title = element_blank(),
      legend.text = element_text(size = 9.5),
      legend.background = element_rect(fill = alpha("white", 0.85), colour = NA)
    )
}
top_changes <- readr::read_csv(
  file.path(project_root, "outputs", "tables", "figure3-top-changing-metabolites.csv"),
  show_col_types = FALSE
)
make_top_change <- function(state_name) {
  top_changes %>%
    filter(state == state_name) %>%
    slice_head(n = 10) %>%
    mutate(
      significance = -log10(pmax(fdr, 1e-300)),
      fdr_label = if_else(fdr < 0.001, format(fdr, scientific = TRUE, digits = 2), format(round(fdr, 3), nsmall = 3)),
      label_short = paste0(str_trunc(label, 26), "\nFDR = ", fdr_label),
      label_short = factor(label_short, levels = rev(label_short))
    ) %>%
    ggplot(aes(effect, label_short, size = significance, colour = direction)) +
    geom_point(alpha = 0.82) +
    geom_vline(xintercept = 0, linewidth = 0.3) +
    scale_colour_manual(values = direction_cols, guide = "none") +
    scale_size_continuous(
      name = expression(-log[10]("BH-adjusted FDR")),
      range = c(3.5, 11),
      breaks = scales::breaks_pretty(n = 3)
    ) +
    labs(title = "Top 10 changed features", x = "log2 fold change", y = NULL) +
    theme_figure3(14.5) +
    theme(
      axis.text.y = element_text(size = 9.6, lineheight = 0.9),
      plot.title = element_text(size = 15),
      legend.position = "bottom",
      legend.title = element_text(size = 10.5),
      legend.text = element_text(size = 9.5),
      legend.key.width = unit(0.7, "cm")
    )
}
