prevalence_plot_data <- combined_prevalence %>%
  mutate(
    confidence.level = factor(paste0("Level ", confidence.level), levels = paste0("Level ", 1:3)),
    category = factor(category, levels = c("Common", "Shared", "Pool-unique")),
    pool_category = factor(paste(combined_pool_id, category, sep = "::"), levels = pool_prevalence_levels),
    label_colour = if_else(category == "Common", "white", "black")
  ) %>%
  arrange(confidence.level, combined_pool_id, category) %>%
  group_by(confidence.level, combined_pool_id) %>%
  mutate(
    label_ymin = lag(cumsum(annotations), default = 0),
    label_ymax = cumsum(annotations),
    label_y = if_else(annotations < 40, label_ymax + 20, (label_ymin + label_ymax) / 2)
  ) %>%
  ungroup()
p_prevalence <- prevalence_plot_data %>%
  ggplot(aes(combined_pool_id, annotations, fill = pool_category)) +
  # Keep the visual order fixed: common at the baseline, shared in the middle,
  # pool-unique at the top. Label y-positions are precomputed above so colour
  # aesthetics cannot accidentally alter the text stack order.
  geom_col(position = position_stack(reverse = TRUE)) +
  geom_text(
    aes(y = label_y, label = fmt_int(annotations), colour = label_colour),
    size = 4.2,
    family = "Arial",
    fontface = "bold",
    show.legend = FALSE
  ) +
  facet_wrap(~confidence.level, nrow = 1) +
  scale_fill_manual(
    values = pool_prevalence_cols,
    breaks = paste("Pool_1", c("Common", "Shared", "Pool-unique"), sep = "::"),
    labels = c("Common", "Shared", "Pool-unique"),
    name = "Prevalence",
    guide = guide_legend(nrow = 1, override.aes = list(linewidth = 0))
  ) +
  scale_colour_identity() +
  scale_y_continuous(expand = expansion(mult = c(0.02, 0.08))) +
  labs(
    title = "Combined crude and fraction annotations across pools",
    x = NULL,
    y = "Non-repeating annotations"
  ) +
  theme(axis.text.x = element_text(angle = 35, hjust = 1), legend.position = "top")

p_class_data <- combined_common_classes %>%
  filter(superclass != "Unclassified") %>%
  arrange(desc(annotations)) %>%
  slice_head(n = 10) %>%
  mutate(
    superclass_plot = superclass,
    superclass_plot = factor(superclass_plot, levels = rev(unique(superclass_plot[order(annotations)])))
  ) %>%
  group_by(superclass_plot) %>%
  summarise(annotations = sum(annotations), .groups = "drop") %>%
  mutate(
    fraction = annotations / sum(annotations),
    label = if_else(fraction >= 0.05, paste0(fmt_int(annotations), "\n", superclass_plot), "")
  )
